import{_ as e,o as a,c as r,a2 as l}from"./chunks/framework.BWuWLRhz.js";const _=JSON.parse('{"title":"劳动合同解除的实务要点梳理","description":"结合现行法律法规，梳理用人单位单方解除劳动合同的法定情形、程序要件及法律后果","frontmatter":{"title":"劳动合同解除的实务要点梳理","date":"2025-07-12T00:00:00.000Z","sort":1,"description":"结合现行法律法规，梳理用人单位单方解除劳动合同的法定情形、程序要件及法律后果","head":[["meta",{"property":"og:title","content":"劳动合同解除的实务要点梳理"}],["meta",{"property":"og:description","content":"结合现行法律法规，梳理用人单位单方解除劳动合同的法定情形、程序要件及法律后果"}],["meta",{"property":"og:image","content":"https://你的域名.com/images/og-default.png"}],["meta",{"property":"og:url","content":"https://你的域名.com/articles/2025-07-12-劳动合同解除实务分析"}],["meta",{"property":"twitter:title","content":"劳动合同解除的实务要点梳理"}],["meta",{"property":"twitter:description","content":"结合现行法律法规，梳理用人单位单方解除劳动合同的法定情形、程序要件及法律后果"}],["meta",{"property":"twitter:image","content":"https://你的域名.com/images/og-default.png"}]]},"headers":[],"relativePath":"articles/2025-07-12-劳动合同解除实务分析.md","filePath":"articles/2025-07-12-劳动合同解除实务分析.md","lastUpdated":null}'),i={name:"articles/2025-07-12-劳动合同解除实务分析.md"};function o(d,t,n,h,s,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="劳动合同解除的实务要点梳理" tabindex="-1">劳动合同解除的实务要点梳理 <a class="header-anchor" href="#劳动合同解除的实务要点梳理" aria-label="Permalink to &quot;劳动合同解除的实务要点梳理&quot;">​</a></h1><h2 id="一、法律依据" tabindex="-1">一、法律依据 <a class="header-anchor" href="#一、法律依据" aria-label="Permalink to &quot;一、法律依据&quot;">​</a></h2><p>用人单位单方解除劳动合同，主要依据《中华人民共和国劳动合同法》第三十九条（过失性解除）、第四十条（非过失性解除）及第四十一条（经济性裁员）。</p><h2 id="二、过失性解除-第三十九条" tabindex="-1">二、过失性解除（第三十九条） <a class="header-anchor" href="#二、过失性解除-第三十九条" aria-label="Permalink to &quot;二、过失性解除（第三十九条）&quot;">​</a></h2><p>用人单位无需支付经济补偿，但需承担举证责任：</p><ol><li>试用期被证明不符合录用条件</li><li>严重违反用人单位规章制度</li><li>严重失职、营私舞弊，造成重大损害</li><li>劳动者同时与其他单位建立劳动关系，对完成本单位工作造成严重影响</li><li>以欺诈手段使对方在违背真实意思情况下订立合同</li><li>被依法追究刑事责任</li></ol><h3 id="实务提示" tabindex="-1">实务提示 <a class="header-anchor" href="#实务提示" aria-label="Permalink to &quot;实务提示&quot;">​</a></h3><ul><li>&quot;严重违反&quot;的认定标准需在规章制度中明确</li><li>解除前应充分调查取证，建议形成书面调查记录</li><li>应通知工会并听取意见</li></ul><h2 id="三、非过失性解除-第四十条" tabindex="-1">三、非过失性解除（第四十条） <a class="header-anchor" href="#三、非过失性解除-第四十条" aria-label="Permalink to &quot;三、非过失性解除（第四十条）&quot;">​</a></h2><p>用人单位需支付经济补偿（N或N+1）：</p><ol><li>劳动者患病或非因工负伤，医疗期满不能从事原工作</li><li>劳动者不胜任工作，经培训或调岗后仍不胜任</li><li>客观情况发生重大变化，合同无法继续履行</li></ol><h2 id="四、程序要件" tabindex="-1">四、程序要件 <a class="header-anchor" href="#四、程序要件" aria-label="Permalink to &quot;四、程序要件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>步骤</th><th>要求</th></tr></thead><tbody><tr><td>事实调查</td><td>收集证据，形成书面记录</td></tr><tr><td>工会通知</td><td>事先将理由通知工会</td></tr><tr><td>书面通知</td><td>出具《解除劳动合同通知书》</td></tr><tr><td>送达确认</td><td>确保劳动者收到解除通知</td></tr><tr><td>离职结算</td><td>结清工资，办理退工手续</td></tr></tbody></table><h2 id="五、法律后果" tabindex="-1">五、法律后果 <a class="header-anchor" href="#五、法律后果" aria-label="Permalink to &quot;五、法律后果&quot;">​</a></h2><ul><li>违法解除：支付赔偿金（2N）</li><li>合法解除（过失性）：无需支付经济补偿</li><li>合法解除（非过失性）：支付经济补偿（N或N+1）</li></ul><hr><blockquote><p><strong>免责声明</strong>：本文仅供学术交流，不构成法律意见。个案情况复杂，具体情况请咨询执业律师。</p></blockquote>',17)])])}const u=e(i,[["render",o]]);export{_ as __pageData,u as default};
